static const double g_RwrStudentExpertBias[4] = { 0.769806206, -0.313379556, 0.991562665, 0.775624394 };

static const double g_RwrStudentOutputMu = 4.05135775;
static const double g_RwrStudentOutputInvSigma = 1.03664231;

static inline double Rwr_StudentInferDelay( const double * pFeatures )
{
    double x[RWR_STUDENT_INPUT_DIM];
    double h[RWR_STUDENT_HIDDEN_DIM];
    double Logits[RWR_STUDENT_NUM_EXPERTS];
    double yLog;
    double yScaled;
    int i, j, BestExpert;
    for ( i = 0; i < RWR_STUDENT_INPUT_DIM; ++i )
        x[i] = (pFeatures[i] - g_RwrStudentInputMu[i]) * g_RwrStudentInputInvSigma[i];
    for ( i = 0; i < RWR_STUDENT_HIDDEN_DIM; ++i )
    {
        double Sum = g_RwrStudentSharedBias[i];
        for ( j = 0; j < RWR_STUDENT_INPUT_DIM; ++j )
            Sum += g_RwrStudentSharedWeight[i][j] * x[j];
        h[i] = Sum > 0.0 ? Sum : 0.0;
    }
    BestExpert = 0;
    for ( i = 0; i < RWR_STUDENT_NUM_EXPERTS; ++i )
    {
        double Sum = g_RwrStudentGateBias[i];
        for ( j = 0; j < RWR_STUDENT_HIDDEN_DIM; ++j )
            Sum += g_RwrStudentGateWeight[i][j] * h[j];
        Logits[i] = Sum;
        if ( i > 0 && Logits[BestExpert] < Logits[i] )
            BestExpert = i;
    }
    yScaled = g_RwrStudentExpertBias[BestExpert];
    for ( j = 0; j < RWR_STUDENT_HIDDEN_DIM; ++j )
        yScaled += g_RwrStudentExpertWeight[BestExpert][j] * h[j];
    yLog = yScaled / g_RwrStudentOutputInvSigma + g_RwrStudentOutputMu;
    if ( yLog < -10.0 ) yLog = -10.0;
    if ( yLog > 10.0 ) yLog = 10.0;
    return exp(yLog) - 1.0;
}

